import React, { useState } from "react";
import AudioUpload from "./components/AudioUpload";
import AudioPlayerComponent from "./components/AudioPlayer";
import AudioEditor from "./components/AudioEditor";
import "./App.css";

const App = () => {
    const [uploadedAudio, setUploadedAudio] = useState(null);
    const [processedAudio, setProcessedAudio] = useState(null);

    const handleUploadSuccess = (audioData) => {
        setUploadedAudio(audioData.filePath); // Path of the uploaded file
        setProcessedAudio(audioData.processedPath); // Path of the processed file
    };

    return (
        <div className="app">
            <h1>Audio Customizer</h1>
            <AudioUpload onUploadSuccess={handleUploadSuccess} />
            {uploadedAudio && (
                <>
                    <h2>Uploaded Audio</h2>
                    <AudioPlayerComponent audioUrl={`http://localhost:5000/${uploadedAudio}`} />
                </>
            )}
            {processedAudio && (
                <>
                    <h2>Processed Audio</h2>
                    <AudioPlayerComponent audioUrl={`http://localhost:5000/${processedAudio}`} />
                </>
            )}
            <AudioEditor />
        </div>
    );
};

export default App;
